173→                let heading = null;
174→                let quote = false;
175→                let alignment = 'left';
176→                let listType = null;
177→                let isCodeBlock = false;
178→                let isLink = false;
179→
180→                if (element) {
181→                    if ($isHeadingNode(element)) {
