221→                    italic,
222→                    underline,
223→                    strikethrough,
224→                    inlineCode,
225→                    heading,
226→                    quote,
227→                    alignment,
228→                    textColor,
229→                    highlightColor,
230→                    listType,
231→                    isCodeBlock,
232→                    isLink,
233→                    canUndo: prev.canUndo,
